4137   // Create the dispatch block (or reuse the single exit block if only one
4138   // exit). The dispatch block computes the first active lane of the combined
4139   // condition and, for multiple exits, chains through conditions to determine
4140   // which exit to take.
4141   VPBasicBlock *DispatchVPBB =
4142       Exits.size() == 1 ? VectorEarlyExitVPBBs[0]
4143                         : Plan.createVPBasicBlock("vector.early.exit.check");
4144   VPBuilder DispatchBuilder(DispatchVPBB, DispatchVPBB->begin());
4145   VPValue *FirstActiveLane =
4146       DispatchBuilder.createNaryOp(VPInstruction::FirstActiveLane, {Combined},
4147                                    DebugLoc::getUnknown(), "first.active.lane");
