4178     auto &[EarlyExitingVPBB, EarlyExitVPBB, _] = Exit;
4179     // Adjust the phi nodes in EarlyExitVPBB.
4180     //   1. remove incoming values from EarlyExitingVPBB,
4181     //   2. extract the incoming value at FirstActiveLane
4182     //   3. add back the extracts as last operands for the phis
4183     // Then adjust the CFG, removing the edge between EarlyExitingVPBB and
