4185     // EarlyExitVPBB. The extracts at FirstActiveLane are now the incoming
4186     // values from VectorEarlyExitVPBB.
4187     for (VPRecipeBase &R : EarlyExitVPBB->phis()) {
4188       auto *ExitIRI = cast<VPIRPhi>(&R);
4189       VPValue *IncomingVal =
