4195             VPInstruction::ExtractLane, {FirstActiveLane, IncomingVal},
4196             DebugLoc::getUnknown(), "early.exit.value");
4197       }
4198       ExitIRI->removeIncomingValueFor(EarlyExitingVPBB);
4199       ExitIRI->addOperand(NewIncoming);
4200     }
4201 
4202     EarlyExitingVPBB->getTerminator()->eraseFromParent();
4203     VPBlockUtils::disconnectBlocks(EarlyExitingVPBB, EarlyExitVPBB);
4204     VPBlockUtils::connectBlocks(VectorEarlyExitVPBB, EarlyExitVPBB);
4205   }
4206 
4207   // Chain through exits: for each exit, check if its condition is true at
4208   // the first active lane. If so, take that exit; otherwise, try the next.
4209   // The last exit needs no check since it must be taken if all others fail.
4210   //
4211   // For 3 exits (cond.0, cond.1, cond.2), this creates:
4212   //
4213   // latch:
4214   //   ...
4215   //   EMIT vp<%combined> = logical-or vp<%cond.0>, vp<%cond.1>, vp<%cond.2>
4216   //   ...
4217   //
4218   // vector.early.exit.check:
4219   //   EMIT vp<%first.lane> = first-active-lane vp<%combined>
4220   //   EMIT vp<%at.cond.0> = extract-lane vp<%first.lane>, vp<%cond.0>
4221   //   EMIT branch-on-cond vp<%at.cond.0>
4222   // Successor(s): vector.early.exit.0, vector.early.exit.check.0
4223   //
4224   // vector.early.exit.check.0:
4225   //   EMIT vp<%at.cond.1> = extract-lane vp<%first.lane>, vp<%cond.1>
4226   //   EMIT branch-on-cond vp<%at.cond.1>
4227   // Successor(s): vector.early.exit.1, vector.early.exit.2
4228   VPBasicBlock *CurrentBB = DispatchVPBB;
4229   for (auto [I, Exit] : enumerate(ArrayRef(Exits).drop_back())) {
4230     VPValue *LaneVal = DispatchBuilder.createNaryOp(
4231         VPInstruction::ExtractLane, {FirstActiveLane, Exit.CondToExit},
4232         DebugLoc::getUnknown(), "exit.cond.at.lane");
4233 
4234     // For the last dispatch, branch directly to the last exit on false;
4235     // otherwise, create a new check block.
4236     bool IsLastDispatch = (I + 2 == Exits.size());
4237     VPBasicBlock *FalseBB =
4238         IsLastDispatch ? VectorEarlyExitVPBBs.back()
4239                        : Plan.createVPBasicBlock(
4240                              Twine("vector.early.exit.check.") + Twine(I));
4241 
4242     DispatchBuilder.createNaryOp(VPInstruction::BranchOnCond, {LaneVal});
4243     CurrentBB->setSuccessors({VectorEarlyExitVPBBs[I], FalseBB});
4244     VectorEarlyExitVPBBs[I]->setPredecessors({CurrentBB});
4245     FalseBB->setPredecessors({CurrentBB});
4246 
4247     CurrentBB = FalseBB;
4248     DispatchBuilder.setInsertPoint(CurrentBB);
4249   }
4250 
4251   // Replace the latch terminator with the new branching logic.
4252   auto *LatchExitingBranch = cast<VPInstruction>(LatchVPBB->getTerminator());
4253   assert(LatchExitingBranch->getOpcode() == VPInstruction::BranchOnCount &&
4254          "Unexpected terminator");
