1821       }
1822 
1823       if (!IsSafeOperation(&I)) {
1824         reportVectorizationFailure("Early exit loop contains operations that "
1825                                    "cannot be speculatively executed",
1826                                    "UnsafeOperationsEarlyExitLoop", ORE,
1827                                    TheLoop);
