1883 bool LoopVectorizationLegality::canUncountableExitConditionLoadBeMoved(
1884     BasicBlock *ExitingBlock) {
1885   // Try to find a load in the critical path for the uncountable exit condition.
1886   // This is currently matching about the simplest form we can, expecting
1887   // only one in-loop load, the result of which is directly compared against
1888   // a loop-invariant value.
1889   // FIXME: We're insisting on a single use for now, because otherwise we will
1890   // need to make PHI nodes for other users. That can be done once the initial
1891   // transform code lands.
1892   auto *Br = cast<BranchInst>(ExitingBlock->getTerminator());
1893 
1894   using namespace llvm::PatternMatch;
1895   Instruction *L = nullptr;
1896   Value *Ptr = nullptr;
1897   Value *R = nullptr;
1898   if (!match(Br->getCondition(),
1899              m_OneUse(m_ICmp(m_OneUse(m_Instruction(L, m_Load(m_Value(Ptr)))),
1900                              m_Value(R))))) {
1901     reportVectorizationFailure(
1902         "Early exit loop with store but no supported condition load",
1903         "NoConditionLoadForEarlyExitLoop", ORE, TheLoop);
1904     return false;
1905   }
1906 
1907   // FIXME: Don't rely on operand ordering for the comparison.
1908   if (!TheLoop->isLoopInvariant(R)) {
1909     reportVectorizationFailure(
1910         "Early exit loop with store but no supported condition load",
1911         "NoConditionLoadForEarlyExitLoop", ORE, TheLoop);
1912     return false;
1913   }
1914 
1915   // Make sure that the load address is not loop invariant; we want an
1916   // address calculation that we can rotate to the next vector iteration.
1917   const auto *AR = dyn_cast<SCEVAddRecExpr>(PSE.getSE()->getSCEV(Ptr));
1918   if (!AR || AR->getLoop() != TheLoop || !AR->isAffine()) {
1919     reportVectorizationFailure(
1920         "Uncountable exit condition depends on load with an address that is "
1921         "not an add recurrence in the loop",
1922         "EarlyExitLoadInvariantAddress", ORE, TheLoop);
1923     return false;
1924   }
1925 
1926   // FIXME: Support gathers after first-faulting load support lands.
1927   SmallVector<const SCEVPredicate *, 4> Predicates;
1928   LoadInst *Load = cast<LoadInst>(L);
1929   if (!isDereferenceableAndAlignedInLoop(Load, TheLoop, *PSE.getSE(), *DT, AC,
1930                                          &Predicates)) {
1931     reportVectorizationFailure(
1932         "Loop may fault",
1933         "Cannot vectorize potentially faulting early exit loop",
1934         "PotentiallyFaultingEarlyExitLoop", ORE, TheLoop);
1935     return false;
1936   }
1937 
1938   ICFLoopSafetyInfo SafetyInfo;
1939   SafetyInfo.computeLoopSafetyInfo(TheLoop);
1940   // We need to know that load will be executed before we can hoist a
1941   // copy out to run just before the first iteration.
1942   if (!SafetyInfo.isGuaranteedToExecute(*Load, DT, TheLoop)) {
1943     reportVectorizationFailure(
1944         "Load for uncountable exit not guaranteed to execute",
1945         "ConditionalUncountableExitLoad", ORE, TheLoop);
1946     return false;
1947   }
