2104 bool LoopVectorizationLegality::canFoldTailByMasking() const {
2105   // The only loops we can vectorize without a scalar epilogue, are loops with
2106   // a bottom-test and a single exiting block. We'd have to handle the fact
2107   // that not every instruction executes on the last iteration.  This will
2108   // require a lane mask which varies through the vector loop body.  (TODO)
2109   if (TheLoop->getExitingBlock() != TheLoop->getLoopLatch()) {
2110     LLVM_DEBUG(
2111         dbgs()
2112         << "LV: Cannot fold tail by masking. Requires a singe latch exit\n");
2113     return false;
2114   }
2115 
2116   LLVM_DEBUG(dbgs() << "LV: checking if tail can be folded by masking.\n");
2117 
2118   SmallPtrSet<const Value *, 8> ReductionLiveOuts;
2119 
2120   for (const auto &Reduction : getReductionVars())
2121     ReductionLiveOuts.insert(Reduction.second.getLoopExitInstr());
2122 
2123   // The list of pointers that we can safely read and write to remains empty.
2124   SmallPtrSet<Value *, 8> SafePointers;
2125 
2126   // Check all blocks for predication, including those that ordinarily do not
2127   // need predication such as the header block.
2128   SmallPtrSet<const Instruction *, 8> TmpMaskedOp;
2129   for (BasicBlock *BB : TheLoop->blocks()) {
2130     if (!blockCanBePredicated(BB, SafePointers, TmpMaskedOp)) {
2131       LLVM_DEBUG(dbgs() << "LV: Cannot fold tail by masking.\n");
2132       return false;
2133     }
2134   }
2135 
2136   LLVM_DEBUG(dbgs() << "LV: can fold tail by masking.\n");
2137 
2138   return true;
2139 }
